# Base module defining shapes hierarchy
# Exports: Shape class and Drawable interface

class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "Shape: " + self.name

interface Drawable:
    def draw(self) -> str: ...

